import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { describe, expect, test } from '@a0n/gnosis/test';
import {
  resolveMutationTheoremMapPath,
  resolveTheoremIdsForMutant,
} from './mutation-theorem-map';

describe('resolveTheoremIdsForMutant', () => {
  test('maps mutator name', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'LeanProofCheck',
      fileKey: 'unrelated/path.ts',
    });
    expect(ids).toContain('THM-PARSER-CLOSURE');
  });

  test('maps longest path prefix', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'unknown',
      fileKey: 'lean/Lean/ForkRaceFoldTheorems/CacheObservation.lean',
    });
    expect(ids).toEqual(['THM-CALLBACK-RESONANCE']);
  });

  test('merges mutator and path mappings', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'LeanProofCheck',
      fileKey: 'lean/Lean/ForkRaceFoldTheorems/FailureEntropy.lean',
    });
    expect(ids.sort()).toEqual(
      ['THM-FAIL-ENTROPY', 'THM-PARSER-CLOSURE'].sort()
    );
  });

  test('maps transformation family theorem ids by Lean path', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'unknown',
      fileKey: 'lean/Lean/ForkRaceFoldTheorems/TransformationFamily.lean',
    });
    expect(ids.sort()).toEqual(
      [
        'THM-TRANSFORMATION-PROJECTION-ADDS-STRUCTURE',
        'THM-TRANSFORMATION-REINFORCEMENT-PRESERVES-STRUCTURE',
        'THM-TRANSFORMATION-DECOMPOSITION-NONINCREASING',
        'THM-TRANSFORMATION-PROJECTION-REINFORCEMENT-EXCLUSIVE',
        'THM-TRANSFORMATION-REINFORCEMENT-DECOMPOSITION-EXCLUSIVE',
        'THM-TRANSFORMATION-FEATURELESS-CANNOT-REINFORCE',
        'THM-TRANSFORMATION-DECOMPOSE-THEN-REINFORCE-REQUIRES-RESTORATION',
      ].sort()
    );
  });

  test('maps decomposition topology theorem ids by runtime path', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'unknown',
      fileKey: 'src/decomposition-topology.ts',
    });
    expect(ids).toEqual(['THM-TRANSFORMATION-DECOMPOSITION-NONINCREASING']);
  });

  test('maps transformation family theorem ids by reducer path', () => {
    const ids = resolveTheoremIdsForMutant({
      mutatorName: 'unknown',
      fileKey: 'src/transformation-family-formalization.ts',
    });
    expect(ids.sort()).toEqual(
      [
        'THM-TRANSFORMATION-PROJECTION-ADDS-STRUCTURE',
        'THM-TRANSFORMATION-REINFORCEMENT-PRESERVES-STRUCTURE',
        'THM-TRANSFORMATION-DECOMPOSITION-NONINCREASING',
        'THM-TRANSFORMATION-PROJECTION-REINFORCEMENT-EXCLUSIVE',
        'THM-TRANSFORMATION-REINFORCEMENT-DECOMPOSITION-EXCLUSIVE',
        'THM-TRANSFORMATION-FEATURELESS-CANNOT-REINFORCE',
        'THM-TRANSFORMATION-DECOMPOSE-THEN-REINFORCE-REQUIRES-RESTORATION',
      ].sort()
    );
  });

  test('resolves bundled absolute module paths without URL parsing', () => {
    const moduleFilePath = fileURLToPath(import.meta.url);

    expect(resolveMutationTheoremMapPath(moduleFilePath)).toBe(
      resolve(dirname(moduleFilePath), 'data', 'mutation-theorem-map.json')
    );
  });

  test('falls back when module url metadata is unavailable', () => {
    expect(resolveMutationTheoremMapPath(undefined)).toContain(
      'mutation-theorem-map.json'
    );
  });
});
